import React, { useEffect, useRef, useState } from "react";
import "../styles/GeneralChat.css";
import therapistResponses from "../data/therapistResponses";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const chatEndRef = useRef(null);

  // Scroll to bottom
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  // Initial bot message
  useEffect(() => {
    setMessages([
      {
        sender: "bot",
        text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      },
    ]);
  }, []);

  // Therapist reply logic (KEY FIX)
  const getTherapistReply = (userText) => {
    const text = userText.toLowerCase();

    const matched = therapistResponses.find((item) =>
      item.keywords.some((keyword) => text.includes(keyword))
    );

    return matched
      ? matched.reply
      : "Thank you for sharing that. I’m here with you. Would you like to tell me a bit more?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setTyping(true);

    setTimeout(() => {
      const botReply = getTherapistReply(userMessage.text);

      setMessages((prev) => [
        ...prev,
        { sender: "bot", text: botReply },
      ]);

      setTyping(false);
    }, 1200);
  };

  return (
    <div className="chat-page">
      {/* HEADER */}
      <div className="chat-header">
        <div>
          <h2>🧠 General Chat</h2>
          <span className="listening">❤️ Listening</span>
        </div>
      </div>

      {/* CHAT BODY */}
      <div className="chat-body">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message ${msg.sender === "user" ? "user" : "bot"}`}
          >
            <div className="bubble">{msg.text}</div>
          </div>
        ))}

        {/* Typing indicator */}
        {typing && (
          <div className="message bot">
            <div className="typing">
              <span></span>
              <span></span>
              <span></span>
            </div>
          </div>
        )}

        <div ref={chatEndRef} />
      </div>

      {/* INPUT */}
      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
